"use strict";(globalThis.webpackChunkui_automata=globalThis.webpackChunkui_automata||[]).push([[8581],{5610(e){e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"Introduction","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"What is UI Automata?","href":"/docs/introduction/what-is-ui-automata","docId":"introduction/what-is-ui-automata"},{"type":"link","label":"Why not vision?","href":"/docs/introduction/why-not-vision","docId":"introduction/why-not-vision"},{"type":"link","label":"Comparison","href":"/docs/introduction/comparison","docId":"introduction/comparison"}]},{"type":"category","label":"Installation","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"System Requirements","href":"/docs/installation/system-requirements","docId":"installation/system-requirements"},{"type":"link","label":"Installation","href":"/docs/installation/desktop-setup","docId":"installation/desktop-setup"},{"type":"link","label":"Connecting MCP","href":"/docs/installation/mcp-tool","docId":"installation/mcp-tool"}]},{"type":"category","label":"Core Concepts","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Workflow Engine","href":"/docs/core-concepts/workflow-engine","docId":"core-concepts/workflow-engine"},{"type":"link","label":"Phases","href":"/docs/core-concepts/phases","docId":"core-concepts/phases"},{"type":"link","label":"Steps & Expects","href":"/docs/core-concepts/steps-and-expects","docId":"core-concepts/steps-and-expects"},{"type":"link","label":"Anchors","href":"/docs/core-concepts/anchors","docId":"core-concepts/anchors"},{"type":"link","label":"Shadow DOM","href":"/docs/core-concepts/shadow-dom","docId":"core-concepts/shadow-dom"},{"type":"link","label":"Selectors","href":"/docs/core-concepts/selectors","docId":"core-concepts/selectors"},{"type":"link","label":"Actions","href":"/docs/core-concepts/actions","docId":"core-concepts/actions"},{"type":"link","label":"Conditions","href":"/docs/core-concepts/conditions","docId":"core-concepts/conditions"},{"type":"link","label":"Params & Outputs","href":"/docs/core-concepts/parameters-and-outputs","docId":"core-concepts/parameters-and-outputs"},{"type":"link","label":"Expressions","href":"/docs/core-concepts/expressions","docId":"core-concepts/expressions"},{"type":"link","label":"Recovery Handlers","href":"/docs/core-concepts/recovery-handlers","docId":"core-concepts/recovery-handlers"},{"type":"link","label":"Control Flow","href":"/docs/core-concepts/control-flow","docId":"core-concepts/control-flow"}]},{"type":"category","label":"Writing Workflows","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Exploring the UI","href":"/docs/writing-workflows/exploring-unknown-ui","docId":"writing-workflows/exploring-unknown-ui"},{"type":"link","label":"Launch & Mount","href":"/docs/writing-workflows/launch-app","docId":"writing-workflows/launch-app"},{"type":"link","label":"Actions in Depth","href":"/docs/writing-workflows/run-actions","docId":"writing-workflows/run-actions"},{"type":"link","label":"Choosing Anchors","href":"/docs/writing-workflows/declaring-anchors","docId":"writing-workflows/declaring-anchors"},{"type":"link","label":"Writing Selectors","href":"/docs/writing-workflows/writing-selectors","docId":"writing-workflows/writing-selectors"},{"type":"link","label":"Extracting Data","href":"/docs/writing-workflows/extracting-data","docId":"writing-workflows/extracting-data"},{"type":"link","label":"Handling Popups","href":"/docs/writing-workflows/handling-popups","docId":"writing-workflows/handling-popups"},{"type":"link","label":"Schema & IDE","href":"/docs/writing-workflows/schema-and-ide","docId":"writing-workflows/schema-and-ide"},{"type":"link","label":"Linting","href":"/docs/writing-workflows/linting","docId":"writing-workflows/linting"},{"type":"link","label":"Subflows","href":"/docs/writing-workflows/subflows","docId":"writing-workflows/subflows"},{"type":"link","label":"Running Scripts","href":"/docs/writing-workflows/running-scripts","docId":"writing-workflows/running-scripts"},{"type":"link","label":"Browser Automation","href":"/docs/writing-workflows/browser-automation","docId":"writing-workflows/browser-automation"}]},{"type":"category","label":"Workflow Library","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Overview","href":"/docs/workflow-library/overview","docId":"workflow-library/overview"},{"type":"link","label":"Office","href":"/docs/workflow-library/office","docId":"workflow-library/office"},{"type":"link","label":"Windows Settings","href":"/docs/workflow-library/windows-settings","docId":"workflow-library/windows-settings"},{"type":"link","label":"Control Panel","href":"/docs/workflow-library/control-panel","docId":"workflow-library/control-panel"},{"type":"link","label":"Explorer","href":"/docs/workflow-library/explorer","docId":"workflow-library/explorer"},{"type":"link","label":"Contributing","href":"/docs/workflow-library/contributing","docId":"workflow-library/contributing"}]},{"type":"category","label":"AI Agent Integration","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"MCP Tools Reference","href":"/docs/ai-agent-integration/mcp-tools","docId":"ai-agent-integration/mcp-tools"},{"type":"link","label":"File & System","href":"/docs/ai-agent-integration/file-and-system","docId":"ai-agent-integration/file-and-system"}]}]},"docs":{"ai-agent-integration/file-and-system":{"id":"ai-agent-integration/file-and-system","title":"File and System Operations","description":"Beyond UI automation, ui-automata exposes file system and system command capabilities on the connected Windows machine \u2014 useful for reading logs, moving artifacts, running scripts, and gathering diagnostics as part of a larger agent workflow.","sidebar":"tutorialSidebar"},"ai-agent-integration/mcp-tools":{"id":"ai-agent-integration/mcp-tools","title":"MCP Tools Reference","description":"automata-agent exposes all ui-automata capabilities to Claude as MCP tools. Each tool covers a category of operations; within a tool, an action parameter selects the specific operation. This keeps the tool list short and the schema self-documenting.","sidebar":"tutorialSidebar"},"core-concepts/actions":{"id":"core-concepts/actions","title":"Actions","description":"An action is what a step does. Actions range from basic UI interactions like clicking and typing, to reading values out of the UI, to running external scripts. Every action is paired with an expect condition that must be satisfied before the workflow continues.","sidebar":"tutorialSidebar"},"core-concepts/anchors":{"id":"core-concepts/anchors","title":"Anchors","description":"An anchor is a named, cached handle to a live UI element. Rather than re-querying the element tree on every step, you declare anchors once and the engine manages their lifetime \u2014 resolving them lazily and invalidating them when the UI changes.","sidebar":"tutorialSidebar"},"core-concepts/conditions":{"id":"core-concepts/conditions","title":"Conditions","description":"A condition is a boolean predicate the engine polls every 100ms until it passes or the step\'s timeout expires. The same condition types appear as expect, precondition, recovery trigger, and flow-control predicates.","sidebar":"tutorialSidebar"},"core-concepts/control-flow":{"id":"core-concepts/control-flow","title":"Control Flow","description":"Workflows are not always linear. Preconditions allow phases to be skipped when a condition is not met. Phase jumps enable loops and branching. The finally block guarantees cleanup regardless of how a workflow ends.","sidebar":"tutorialSidebar"},"core-concepts/expressions":{"id":"core-concepts/expressions","title":"Expressions","description":"Workflows have two distinct mechanisms for working with values at runtime. Understanding which one to use \u2014 and why they are separate \u2014 avoids confusion.","sidebar":"tutorialSidebar"},"core-concepts/parameters-and-outputs":{"id":"core-concepts/parameters-and-outputs","title":"Parameters and Outputs","description":"Workflows are reusable. Parameters let callers pass values in; outputs let workflows return structured data back to the caller \u2014 whether that is another workflow, an MCP tool call, or a test assertion.","sidebar":"tutorialSidebar"},"core-concepts/phases":{"id":"core-concepts/phases","title":"Phases","description":"A phase is the top-level unit of execution within a workflow. Phases run in order; the first failure stops the workflow. Each phase is one of three kinds: an action phase (steps), a flow-control phase (conditional jump), or a subflow phase (delegates to a child workflow).","sidebar":"tutorialSidebar"},"core-concepts/recovery-handlers":{"id":"core-concepts/recovery-handlers","title":"Recovery Handlers","description":"A workflow is not a flat sequence of steps. It is a hierarchical state machine.","sidebar":"tutorialSidebar"},"core-concepts/selectors":{"id":"core-concepts/selectors","title":"Selectors","description":"The Windows UI Automation element tree is messy. A typical application window contains hundreds of elements: nested panels, unlabelled containers, toolbars with identical-looking buttons, lists where every row has the same role and no name. Individual elements often carry only partial information \u2014 a role but no name, a name but the wrong role, an AutomationId in one OS version but not another.","sidebar":"tutorialSidebar"},"core-concepts/shadow-dom":{"id":"core-concepts/shadow-dom","title":"The Shadow DOM","description":"The shadow DOM is the engine\'s cached mirror of the live Windows UI element tree. It is the core of what makes ui-automata fast and reliable \u2014 fast enough to react to UI transitions in well under a second, and reliable enough to stay locked to the right window even when the desktop is busy.","sidebar":"tutorialSidebar"},"core-concepts/steps-and-expects":{"id":"core-concepts/steps-and-expects","title":"Steps and Expects","description":"A step is the atomic unit of work in a workflow. Each step performs one action, then waits for a condition to become true before the workflow continues.","sidebar":"tutorialSidebar"},"core-concepts/workflow-engine":{"id":"core-concepts/workflow-engine","title":"The Workflow Engine","description":"A workflow file is static YAML. The workflow engine is what runs it. Understanding what the engine does on each step \u2014 and what it does when something goes wrong \u2014 is the foundation for writing workflows that are reliable in practice, not just on the happy path.","sidebar":"tutorialSidebar"},"installation/desktop-setup":{"id":"installation/desktop-setup","title":"Installation","description":"One PowerShell command installs everything: the workflow engine, the MCP tool, and the workflow library.","sidebar":"tutorialSidebar"},"installation/mcp-tool":{"id":"installation/mcp-tool","title":"Connecting MCP","description":"automata-agent is an MCP server that exposes all ui-automata tools to Claude. It ships with the installer and supports two connection modes depending on which Claude client you use.","sidebar":"tutorialSidebar"},"installation/system-requirements":{"id":"installation/system-requirements","title":"System Requirements","description":"ui-automata runs on Windows locally. There is no server and no cloud dependency.","sidebar":"tutorialSidebar"},"introduction/comparison":{"id":"introduction/comparison","title":"How it compares","description":"ui-automata occupies a specific niche in the desktop automation landscape. Here is how it differs from the tools you may already know.","sidebar":"tutorialSidebar"},"introduction/what-is-ui-automata":{"id":"introduction/what-is-ui-automata","title":"What is UI Automata?","description":"UI Automata is a declarative workflow engine for Windows UI automation, designed from the ground up for AI agents. Instead of writing scripts that click at coordinates or sleep-and-hope, you describe what should happen. The engine handles action, recovery, and observability.","sidebar":"tutorialSidebar"},"introduction/why-not-vision":{"id":"introduction/why-not-vision","title":"Why not pure vision-based computer use?","description":"Vision-based computer use (where an AI model looks at screenshots and decides where to click) is the obvious first approach to desktop automation. It works, up to a point. ui-automata takes a different path, and the reasons are worth understanding.","sidebar":"tutorialSidebar"},"workflow-library/contributing":{"id":"workflow-library/contributing","title":"Contributing Workflows","description":"The workflow library grows with real-world usage. If you have a workflow for an application not yet covered, contributions are welcome.","sidebar":"tutorialSidebar"},"workflow-library/control-panel":{"id":"workflow-library/control-panel","title":"Control Panel","description":"The classic Control Panel is a Win32 application (control.exe). These workflows cover settings that have not been migrated to the modern Settings app or that are more conveniently accessed here.","sidebar":"tutorialSidebar"},"workflow-library/explorer":{"id":"workflow-library/explorer","title":"Windows Explorer","description":"File Explorer is a Win32 application on Win10 and a Win11-modern app on Win11 (tabbed interface, new_window launch strategy). These workflows handle both by launching a fresh Explorer window and navigating from there.","sidebar":"tutorialSidebar"},"workflow-library/office":{"id":"workflow-library/office","title":"Microsoft Office","description":"Office applications (Word, Excel, PowerPoint) are native Win32/C++ applications with a custom UI framework that predates .NET. What makes them interesting for automation is that they expose unusually rich UIA automation IDs \u2014 FontSize, TabHome, BackstageView \u2014 on most interactive controls. This gives you stable, locale-independent selectors that survive version updates, which is the best-case scenario for any automation target.","sidebar":"tutorialSidebar"},"workflow-library/overview":{"id":"workflow-library/overview","title":"Workflow Library","description":"The workflow library is a collection of ready-to-use workflows for common Windows applications. Each workflow is a tested, parameterized YAML file you can call directly or compose into larger automations as a subflow.","sidebar":"tutorialSidebar"},"workflow-library/windows-settings":{"id":"workflow-library/windows-settings","title":"Windows Settings","description":"Windows Settings is a UWP app hosted by ApplicationFrameHost.exe, anchored by window title ([name=Settings]). These workflows navigate the modern Settings panels introduced in Win10 and expanded in Win11.","sidebar":"tutorialSidebar"},"writing-workflows/browser-automation":{"id":"writing-workflows/browser-automation","title":"Browser Automation","description":"The workflow engine supports automating a web browser (Microsoft Edge) through two complementary mechanisms:","sidebar":"tutorialSidebar"},"writing-workflows/declaring-anchors":{"id":"writing-workflows/declaring-anchors","title":"Choosing Anchors","description":"Given a real application, how do you decide where to put anchors? This is the most consequential structural decision in a workflow. The right choices make the workflow resilient; the wrong ones produce stale handles and fragile re-query chains.","sidebar":"tutorialSidebar"},"writing-workflows/exploring-unknown-ui":{"id":"writing-workflows/exploring-unknown-ui","title":"Exploring an Unknown UI","description":"Before you can write a selector, you need to know the element tree. ui-automata ships CLI tools for inspecting a live Windows UI \u2014 listing windows, walking the UIA element tree, and testing selectors \u2014 without touching a workflow file.","sidebar":"tutorialSidebar"},"writing-workflows/extracting-data":{"id":"writing-workflows/extracting-data","title":"Extracting Data","description":"Many workflows do not just drive a UI \u2014 they read from it. The Extract action reads a value from a UI element and stores it under a named key. That key is then available as {output.key} in every subsequent step, condition, and expression.","sidebar":"tutorialSidebar"},"writing-workflows/handling-popups":{"id":"writing-workflows/handling-popups","title":"Handling Popups and Dialogs","description":"Popups and dialogs are the most common reason workflows fail. A save prompt appears when you did not expect one; a permission dialog captures focus mid-sequence; a warning blocks the next click. This page covers the patterns for handling each kind.","sidebar":"tutorialSidebar"},"writing-workflows/launch-app":{"id":"writing-workflows/launch-app","title":"Launching an App or Mounting a Window","description":"Before a workflow can interact with a UI, it needs a handle to a window. There are two situations: you need to launch the application yourself, or the application is already running and you need to attach to it.","sidebar":"tutorialSidebar"},"writing-workflows/linting":{"id":"writing-workflows/linting","title":"Linting and Validation","description":"The JSON Schema and the ui-workflow-check linter serve different roles. The schema validates structure \u2014 required fields, enum values, type shapes. The linter validates meaning \u2014 cross-references between parts of the workflow that a schema cannot express.","sidebar":"tutorialSidebar"},"writing-workflows/run-actions":{"id":"writing-workflows/run-actions","title":"Actions in Depth","description":"Actions are the verbs of a workflow. Each step executes exactly one action and then waits for its expect condition. This page covers every action type with practical examples drawn from real workflows.","sidebar":"tutorialSidebar"},"writing-workflows/running-scripts":{"id":"writing-workflows/running-scripts","title":"Running External Scripts","description":"The Exec action runs any executable on the Windows machine: Python scripts, PowerShell, batch files, or any program reachable via PATH. This is the bridge between the workflow engine and the broader scripting ecosystem.","sidebar":"tutorialSidebar"},"writing-workflows/schema-and-ide":{"id":"writing-workflows/schema-and-ide","title":"Schema and IDE Support","description":"ui-automata ships a JSON Schema generated directly from the Rust types that power the executor. Add a single comment to any workflow file and your editor validates your YAML, offers autocomplete for every field, and shows inline documentation for every action and condition type.","sidebar":"tutorialSidebar"},"writing-workflows/subflows":{"id":"writing-workflows/subflows","title":"Composing with Subflows","description":"A subflow phase delegates execution to a child workflow file. The child runs to completion, its declared outputs are returned to the parent, and the parent continues from the next phase.","sidebar":"tutorialSidebar"},"writing-workflows/writing-selectors":{"id":"writing-workflows/writing-selectors","title":"Writing Robust Selectors","description":"A selector that works today can silently stop working after an application update, a locale change, or an OS upgrade. This page covers the practical craft of writing selectors that are precise, stable, and debuggable.","sidebar":"tutorialSidebar"}}}')}}]);